        serviceId: 'srv-test',
        updates: { VAR_A: 'val_a' },
        requiredKeys: [...REQUIRED_KEYS, 'VAR_A'],
        fetchImpl: mockFetch,
      }),
      safeMergeRenderEnvVars({
        renderApiKey: 'rnd_test',
        serviceId: 'srv-test',
        updates: { VAR_B: 'val_b' },
